python3 - <<'PY'
import re
from pathlib import Path
sh=Path('/home/arthur/src/linux/drivers/gpu/drm/amd/include/asic_reg/dcn/dcn_1_0_sh_mask.h').read_text().splitlines()
regs=['DOMAIN0_PG_CONFIG','DOMAIN0_PG_STATUS','DOMAIN1_PG_CONFIG','DOMAIN1_PG_STATUS','DCHUBP_CNTL','HUBP_CLK_CNTL','DPP_CONTROL','OPP_PIPE_CONTROL','DCN_EXPANSION_MODE','DCHUBP_REQ_SIZE_CONFIG','DCSURF_SURFACE_CONTROL','DCSURF_TILING_CONFIG','DCSURF_SURFACE_CONFIG','DCSURF_SURFACE_PITCH','DCSURF_PRI_VIEWPORT_START','DCSURF_PRI_VIEWPORT_DIMENSION','DCSURF_FLIP_CONTROL','HUBPRET_CONTROL','CNVC_SURFACE_PIXEL_FORMAT','CNVC_FORMAT_CONTROL','DSCL_CONTROL','DSCL_RECOUT_START','DSCL_RECOUT_SIZE','DSCL_MPC_SIZE','DSCL_SCL_MODE','MPCC_BOT_SEL','MPCC_CONTROL','MPCC_TOP_SEL','MPCC_OPP_ID','MPCC_UPDATE_LOCK_SEL','MPC_OUT_MUX','VTG_CONTROL','OTG_DOUBLE_BUFFER_CONTROL','OTG_H_TOTAL','OTG_H_SYNC_A','OTG_H_BLANK_START_END','OTG_H_SYNC_A_CNTL','OTG_H_TIMING_CNTL','OTG_V_TOTAL','OTG_V_TOTAL_MIN','OTG_V_TOTAL_MAX','OTG_V_SYNC_A','OTG_V_BLANK_START_END','OTG_V_SYNC_A_CNTL','OTG_INTERLACE_CONTROL','OTG_VSTARTUP_PARAM','OTG_VUPDATE_PARAM','OTG_VREADY_PARAM','OTG_CONTROL','OPTC_INPUT_CLOCK_CONTROL','OTG_CLOCK_CONTROL','OPTC_DATA_SOURCE_SELECT','OTG_BLANK_CONTROL','DCSURF_PRIMARY_ADDRESS_HIGH','DCSURF_PRIMARY_ADDRESS','BLANK_OFFSET_0','BLANK_OFFSET_1','DST_DIMENSIONS','DST_AFTER_SCALER','REF_FREQ_TO_PIX_FREQ','PREFETCH_SETTINS','VBLANK_PARAMETERS_0','PER_LINE_DELIVERY_PRE','PER_LINE_DELIVERY','DCN_TTU_QOS_WM','DCN_SURF0_TTU_CNTL0','DCN_SURF0_TTU_CNTL1','DCN_GLOBAL_TTU_CNTL']
for reg in regs:
    matches=[]
    pat=re.compile(r'#define .*_'+re.escape(reg)+r'__(.*?)__(SHIFT|MASK)\s+(.+)')
    for line in sh:
        m=pat.search(line)
        if m: matches.append((m.group(1),m.group(2),m.group(3).strip()))
    if matches:
        fields={}
        for f,t,v in matches: fields.setdefault(f,{})[t]=v
        print(reg+': '+', '.join(f"{f} shift={d.get('SHIFT')} mask={d.get('MASK')}" for f,d in fields.items()))
PY

